class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        def check(x):
            l, r = max(1, index - x + 1), min(n, index + x)
            return sum(range(l, r + 1)) + (x - 1) * (l - 1) + (x - 1) * (n - r) <= maxSum

        l, r = 1, maxSum // n
        while l < r:
            mid = (l + r + 1) // 2
            if check(mid):
                l = mid
            else:
                r = mid - 1
        return l
